### Fetch User Access Token for CalProvider

Source: https://github.com/calcom/cal.com/blob/main/docs/platform/quickstart.mdx

This snippet shows how to fetch a user's access token and provide it to the CalProvider. It uses the useEffect hook to fetch the token from a '/api/users/:userId' endpoint after the component mounts. The retrieved access token is then passed to CalProvider, enabling authenticated operations for atoms.

```javascript
import "@calcom/atoms/globals.min.css";
import { CalProvider } from '@calcom/atoms';
import { useState, useEffect } from 'react';

function MyApp({ Component, pageProps }) {
  const [accessToken, setAccessToken] = useState("");

  useEffect(() => {
    fetch(`/api/users/${pageProps.userId}`, {
    }).then(async (res) => {
      const data = await res.json();
      setAccessToken(data.accessToken);
    });
  }, []);

  return (
    <CalProvider
      accessToken={accessToken}
      clientId={process.env.CAL_OAUTH_CLIENT_ID ?? ""}
      options={{
        apiUrl: process.env.CAL_API_URL ?? "",
        refreshUrl: "/api/refresh"
      }}
    >
      <Component {...pageProps} />
    </CalProvider>
  );
}

export default MyApp;
```

