### Implement Greeter Button Component

Source: https://github.com/calcom/cal.com/blob/main/docs/developing/guides/appstore-and-integration/build-a-greeter-app.mdx

A React component (GreeterButton.tsx) for Cal.com that displays a 'Greet Me!' button. The button is conditionally rendered only if the user is logged in and the 'greeter' app is installed. Clicking the button displays a success toast message with a greeting.

```typescript
/**
* GreeterButton.tsx
* It creates a button that can be added anywhere. The button is visible only if the app is installed.
*/
import useApp from "@calcom/lib/hooks/useApp";
import showToast from "@calcom/lib/notification";
import { Button } from "@calcom/ui/button/Button";

import useMeQuery from "@calcom/trpc/react/hooks/useMeQuery";

export default function GreeterButton() {
  const { data: user } = useMeQuery();
  const { data: greeterApp } = useApp("greeter");
  // Make sure that greeterApp is installed. We shouldn't show the button when app is not installed
  if (!user || !greeterApp) {
    return null;
  }
  return (
    <Button
      onClick={() => {
        showToast("Hello, " + user.name, "success");
      }}
    >
      Greet Me!
    </Button>
  );
}
```

