### Embed Routing Form with Automatic Parameter Injection

Source: https://github.com/calcom/cal.com/blob/main/packages/embeds/embed-core/routing-playground.html

This script automatically injects necessary parameters like 'only', 'calOrigin', and 'cal.embed.logging' into the URL's search parameters if they are missing. It then redirects the user to the updated URL. This ensures the embed environment is correctly configured for the routing form.

```javascript
if (!location.search.includes("nonResponsive")) { document.write('<meta name="viewport" content="width=device-width"/>'); } 
(function addParamsAutomatically() { 
  const newSearchParams = new URLSearchParams(location.search);
  let paramsChanged = false;
  if (!newSearchParams.has("only")) {
    newSearchParams.set("only", "ns:routingFormFullPrerender");
    paramsChanged = true;
  }
  if (!newSearchParams.has("calOrigin")) {
    newSearchParams.set("calOrigin", "http://acme.cal.local:3000");
    paramsChanged = true;
  }
  if (!newSearchParams.has("cal.embed.logging")) {
    newSearchParams.set("cal.embed.logging", "1");
    paramsChanged = true;
  }
  if (paramsChanged) {
    location.href = "?" + newSearchParams.toString();
  }
})();
```

